INPUT:
interface RawConfig {
  cause: string;
  records: number;
  filter: number;
  path?: boolean;
  total?: string | null;
  file_size: string | null;
  checksum: string;
}
OUTPUT:
RawConfig
  = cause:CauseSection EOL records:RecordsSection EOL filter:FilterSection EOL file_size:FileSizeSection EOL checksum:ChecksumSection path:PathOpt total:TotalOpt EOLopt
    { return { cause: cause, records: records, filter: filter, file_size: file_size, checksum: checksum, path: path, total: total }; }

CauseSection
  = "CAUSE:" _ v:QuotedString { return v; }

RecordsSection
  = "RECORDS:" _ v:Float { return v; }

FilterSection
  = "FILTER:" _ v:Integer { return v; }

FileSizeSection
  = "FILE_SIZE:" _ "none" { return null; }
  / "FILE_SIZE:" _ v:QuotedString { return v; }

ChecksumSection
  = "CHECKSUM:" _ v:QuotedString { return v; }

PathOpt
  = EOL "PATH:" _ v:Bool { return v; }
  / "" { return undefined; }

TotalOpt
  = EOL "TOTAL:" _ "none" { return null; }
  / EOL "TOTAL:" _ v:QuotedString { return v; }
  / "" { return undefined; }

Bool = "yes" { return true; } / "no" { return false; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Float = chars:$([0-9]+ ("." [0-9]+)?) { return parseFloat(chars); }
Integer = chars:$[0-9]+ { return parseInt(chars, 10); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

