    { return { cooldownMinutes: cooldownMinutes, timeoutMs: timeoutMs, ipAddress: ipAddress, tokenCount: tokenCount, latency_ms: latency_ms, patch_level: patch_level, tableName: tableName, summary: summary, nodeId: nodeId, retryCount: retryCount }; }

CooldownMinutesSection
